#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <assert.h>

#include <omp.h>

#define THREADS_PER_DIM 16
#define BLOCKS_PER_DIM 16
#define THREADS_PER_BLOCK (THREADS_PER_DIM*THREADS_PER_DIM)

#define ASSUMED_NR_CLUSTERS 32

#define FLT_MAX 3.40282347e+38

unsigned int num_threads_perdim = THREADS_PER_DIM;					
unsigned int num_blocks_perdim = BLOCKS_PER_DIM;					
unsigned int num_threads;	
unsigned int num_blocks;		

int    *membership_new;												
float  *feature_d;													
float  *feature_flipped_d;											
int    *membership_d;												
float  *block_new_centers;											
float  *clusters_d;													
float  *block_clusters_d;											
int    *block_deltas_d;												

float c_clusters[ASSUMED_NR_CLUSTERS*34];

// Forward declarations
int setup(int argc, char** argv);
float **kmeans_clustering(float **feature, int nfeatures, int npoints, int nclusters, float threshold, int *membership);

void invert_mapping(float *input, float *output, int npoints, int nfeatures)
{
    #pragma omp parallel for schedule(static)
    for (int point_id = 0; point_id < npoints; point_id++) {
        for(int i=0; i<nfeatures; i++)
            output[point_id + npoints*i] = input[point_id*nfeatures + i];
    }
}

void allocateMemory(int npoints, int nfeatures, int nclusters, float **features)
{	
	num_threads = num_threads_perdim*num_threads_perdim;
	num_blocks = npoints / num_threads;
	if (0 < npoints % num_threads)		
		num_blocks++;

	num_blocks_perdim = (unsigned int) sqrt((double) num_blocks);
	while (num_blocks > num_blocks_perdim * num_blocks_perdim)	
		num_blocks_perdim++;

	num_blocks = num_blocks_perdim*num_blocks_perdim;

	membership_new = (int*) malloc(npoints * sizeof(int));
	for(int i=0; i<npoints; i++) {
		membership_new[i] = -1;
	}

	block_new_centers = (float *) malloc(nclusters*nfeatures*sizeof(float));

	feature_flipped_d = (float *) malloc(npoints*nfeatures*sizeof(float));
	memcpy(feature_flipped_d, features[0], npoints*nfeatures*sizeof(float));
	feature_d = (float *) malloc(npoints*nfeatures*sizeof(float));

	invert_mapping(feature_flipped_d,feature_d,npoints,nfeatures);

	membership_d = (int *) malloc(npoints*sizeof(int));
	clusters_d = (float *) malloc(nclusters*nfeatures*sizeof(float));

	block_deltas_d = (int *) malloc(num_blocks_perdim * num_blocks_perdim * sizeof(int));
	block_clusters_d = (float *) malloc(num_blocks_perdim * num_blocks_perdim * nclusters * nfeatures * sizeof(float));
}

void deallocateMemory()
{
	free(membership_new);
	free(block_new_centers);
	free(feature_d);
	free(feature_flipped_d);
	free(membership_d);
	free(clusters_d);
	free(block_clusters_d);
	free(block_deltas_d);
}

int kmeansPoint(float  *features, int nfeatures, int npoints, int nclusters,
                int *membership, float *clusters, float *block_clusters, int *block_deltas)
{
    int delta = 0;

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        int nthreads = omp_get_num_threads();

        int points_per_thread = (npoints + nthreads - 1) / nthreads;
        int start = tid * points_per_thread;
        int end = start + points_per_thread;
        if (end > npoints) end = npoints;

        int local_delta = 0;

        for (int point_id = start; point_id < end; point_id++) {
            int index = -1;
            float min_dist = FLT_MAX;

            for (int i=0; i<nclusters; i++) {
                int cluster_base_index = i*nfeatures;
                float ans=0.0;

                for (int j=0; j<nfeatures; j++) {
                    float diff = features[point_id + j*npoints] - c_clusters[cluster_base_index + j];
                    ans += diff*diff;
                }
                float dist = ans;

                if (min_dist > dist) {
                    min_dist = dist;
                    index = i;
                }
            }

            if (membership[point_id] != index) {
                local_delta++;
            }
            membership[point_id] = index;
        }

        #pragma omp atomic
        delta += local_delta;
    }

    return delta;
}

int	
kmeansCuda(float  **feature, int nfeatures, int npoints, int nclusters,
           int *membership, float **clusters, int *new_centers_len, float **new_centers)
{
	int delta = 0;			
	int i,j;				

	memcpy(membership_d, membership_new, npoints*sizeof(int));
	memcpy(clusters_d, clusters[0], nclusters*nfeatures*sizeof(float));

	memcpy(c_clusters, clusters[0], nclusters*nfeatures*sizeof(float));

	delta = kmeansPoint(feature_d, nfeatures, npoints, nclusters,
                        membership_d, clusters_d, block_clusters_d, block_deltas_d);

	memcpy(membership_new, membership_d, npoints*sizeof(int));	

	delta = 0;
	for (i = 0; i < npoints; i++)
	{		
		int cluster_id = membership_new[i];
		new_centers_len[cluster_id]++;
		if (membership[i] != membership_new[i])
		{
			delta++;
			membership[i] = membership_new[i];
		}
		for (j = 0; j < nfeatures; j++)
		{			
			new_centers[cluster_id][j] += feature[i][j];
		}
	}

	return delta;
}
